import{_ as t,a as i,a3 as o,o as a}from"./chunks/framework.edeurCMZ.js";const m=JSON.parse('{"title":"Event Consumption","description":"","frontmatter":{},"headers":[],"relativePath":"common/eventconsumption/README.md","filePath":"common/eventconsumption/README.md","lastUpdated":1782747484000}'),n={name:"common/eventconsumption/README.md"};function s(d,e,r,c,l,p){return a(),i("div",null,[...e[0]||(e[0]=[o(`<h1 id="event-consumption" tabindex="-1">Event Consumption <a class="header-anchor" href="#event-consumption" aria-label="Permalink to &quot;Event Consumption&quot;">​</a></h1><h1 id="ieventvisitor" tabindex="-1">IEventVisitor <a class="header-anchor" href="#ieventvisitor" aria-label="Permalink to &quot;IEventVisitor&quot;">​</a></h1><p>The <code>readEvents</code> function declared in <code>jevent.hpp</code> follows a push-parsing model for parsing event files created by <code>EventRecorder</code>, declared in the same file. Given a file path and an instance of a visitor implementation, processing consists of these steps:</p><ul><li>The function notifies the visitor that processing of a new file is beginning. The visitor may abort processing at this time.</li><li>The function notifies the visitor of zero or more events. The visitor may abort processing during any of these visits.</li><li>The function notifies the visitor that processing is complete.</li></ul><h2 id="ieventvisitationlink" tabindex="-1">IEventVisitationLink <a class="header-anchor" href="#ieventvisitationlink" aria-label="Permalink to &quot;IEventVisitationLink&quot;">​</a></h2><p>An extension of <code>IEventVisitor</code>, implementations can be combined in a singly linked list of visitors. Each node in the list chooses whether to propagate notification to the next node in the list. When propagating, each node controls what data is passed on.</p><h3 id="ieventfilter" tabindex="-1">IEventFilter <a class="header-anchor" href="#ieventfilter" aria-label="Permalink to &quot;IEventFilter&quot;">​</a></h3><p>An extension of <code>IEventVisitationLink</code>, this abstraction describes visitors whose purpose is to block unwanted events from propagating to the next visitor in the chain. Implementations define the filtering logic. Generally, an implementation will only prevent individual event visitations from propagating.</p><h4 id="ceventfilter" tabindex="-1">CEventFilter <a class="header-anchor" href="#ceventfilter" aria-label="Permalink to &quot;CEventFilter&quot;">​</a></h4><p>A concrete implementation of <code>IEventFilter</code> that classifies all incoming events as either wanted or unwanted. Events that are wanted are propagates, unchanged, to the next linked visitor. Unwanted events are not propagated.</p><p>Filter terms define conditions used to identify wanted events. Conditions may be applied based on event type and event attribute values. All events are considered wanted until at least one filter term is applied.</p><p>Filter terms can be specified through direct manipulation of the filter, or with a configuration property tree. The property tree, without discussing value meaning, is as follows:</p><pre><code>attribute/
</code></pre><p>Optional and repeatable element describing applied to one event attribute.</p><pre><code>attribute/@id
attribute/@values
</code></pre><p>Required attributes identifying an event attribute by its name and the accepted values. See <a href="#filter-by-attribute">Filter by Attribute</a> for valid <code>@values</code> content.</p><pre><code>event/
</code></pre><p>Optional and repeatable element describing a filter for one or more events.</p><pre><code>event/@list
event/@type
event/@context
</code></pre><p>Contextual specification of one or more events to be filtered. A list is a delimited collection of event names. A type is a single event name. A context is an internally defined group of logically related events. List takes precedence over type, which takes precedence over context.</p><p>See <a href="#filter-by-event">Filter by Event</a> for more information about filtering by events.</p><h5 id="filter-by-event" tabindex="-1">Filter by Event <a class="header-anchor" href="#filter-by-event" aria-label="Permalink to &quot;Filter by Event&quot;">​</a></h5><p>An event type term identifies either a single event type or a single event context, implicitly identifying every event type associated with that context.</p><p>Event terms may be specified by the <code>EventType</code> enumeration, the <code>EventCtx</code> enumeration, or a comma-delimited list of event type and/or context names. The list format is described as follows:</p><pre><code>    term-list ::= term ( &#39;,&#39; term )*
    term ::= ( [ type-comparison ] type-term | [ context-comparison ] context-term )
    type-comparison ::= &#39;[&#39; ( &quot;eq&quot; | &quot;neq&quot; | &quot;except&quot; ) &#39;]&#39;
    type-term ::= &lt;event-type-name&gt;
    context-comparison ::= &#39;[&#39; ( &quot;in&quot; | &quot;out&quot; | &quot;except&quot; ) &#39;]&#39;
    context-term ::= &lt;event-context-name&gt;
</code></pre><p>Values of <code>type-comparison</code>, <code>type-term</code>, <code>context-comparison</code>, and <code>context-term</code> are case insensitive.</p><p>By default, all identified types are accumulated into a collection of accepted event types. Optional comparison tokens alter how the term value is interpreted. Events with types in the accumulated type collection are retained, while others are suppressed. Accepted comparisons include:</p><ul><li><code>eq</code> (default): the term type is accumulated</li><li><code>neq</code>: all types except the term type are accumulated</li><li><code>in</code> (default): all event types with the term context are accumulated</li><li><code>out</code>: all event types without the term context are accumulated</li><li><code>except</code>: removes the term value from the accumulated collection <ul><li>If the term value is a type, the type is removed if it was previously accumulated.</li><li>If the term value is a context, all previously accumulated types of the context are removed.</li></ul></li></ul><p>An example using <code>out</code> might be <code>[not]dali</code>. The effect is to accept all events not in the dali event context.</p><p>An example using <code>except</code> might be <code>index,[except]IndexPayload</code>. The effect of this list is to accept all index context events except for IndexPayload.</p><h5 id="filter-by-attribute" tabindex="-1">Filter by Attribute <a class="header-anchor" href="#filter-by-attribute" aria-label="Permalink to &quot;Filter by Attribute&quot;">​</a></h5><p>An event attribute term identifies a single attribute, a set of expected values, and an optional condition relating an event value to expected values. Multiple terms are permitted for one attribute, in which case at least one term must be satisfied. Terms are permitted for multiple attributes, in which case a term for each attribute must be satisfied.</p><p>Terms related to attributes not present in an event are implicitly satisfied. Rules for satisfying terms vary by the attribute data type.</p><h6 id="text" tabindex="-1">Text <a class="header-anchor" href="#text" aria-label="Permalink to &quot;Text&quot;">​</a></h6><p>A comma-delimited list of terms is defined for text attributes, using the following format:</p><pre><code>    term-list ::= term ( &#39;,&#39; term )*
    term ::= [ comparison ] &lt;pattern&gt;
    comparison ::= &#39;[&#39; ( &quot;wild&quot; | &quot;eq&quot; | &quot;neq&quot; | &quot;lt&quot; | &quot;lte&quot; | &quot;gte&quot; | &quot;gt&quot; ) &#39;]&#39;
</code></pre><p>In the absence of <code>comparison</code>, the term text is used as a wilcard matching pattern. Case-insensitive comparisons include:</p><ul><li><code>wild</code> (default): attribute value is a wildcard match of the term pattern</li><li><code>eq</code>: attribute value matches pattern</li><li><code>neq</code>: attribute value does not match pattern</li><li><code>lt</code>: attribute value is less than the term pattern</li><li><code>lte</code>: attribute value is less than or equal to the term pattern</li><li><code>gte</code>: attribute value is greater than or equal to the term pattern</li><li><code>gt</code>: attribute value is greater than the term pattern</li></ul><p>The default <code>wild</code> comparison is the only comparison that considers wildcard substitutions. All others perform simple case-insensitive string comparisons.</p><h6 id="boolean" tabindex="-1">Boolean <a class="header-anchor" href="#boolean" aria-label="Permalink to &quot;Boolean&quot;">​</a></h6><p>A comma-delimited list of terms is defined for text attributes, using the following format:</p><pre><code>    term-list ::= term ( &#39;,&#39; term )
    term ::= &lt;value&gt;
</code></pre><p>A term list is supported by common code. With only two possible values, nothing is gained by adding two terms with different value.</p><h6 id="numeric" tabindex="-1">Numeric <a class="header-anchor" href="#numeric" aria-label="Permalink to &quot;Numeric&quot;">​</a></h6><p>A comma-delimited list of terms is defined for numeric attributes, using the following format:</p><pre><code>    term-list ::= term ( &#39;,&#39; term )*
    term ::= [ comparison ] ( single-value | range | at-most | at-least )
    comparison ::= &#39;[&#39; ( &quot;eq&quot; | &quot;neq&quot; | &quot;lt&quot; | &quot;lte&quot; | &quot;gte&quot; | &quot;gt&quot; | &quot;in&quot; | &quot;out&quot; ) &#39;]&#39;
    single-value ::= &lt;number&gt;
    range ::= single-value &#39;-&#39; single-value
    at-most ::= &#39;-&#39; single-value
    at-least ::= single-value &#39;-&#39;
</code></pre><p>Every term is treated implicitly treated as a range defined as <code>[term-minimum..term-maximum]</code>. The <code>term-minimum</code> must be less than or equal to the <code>term-maximum</code>. Four forms of range specification are accepted:</p><ul><li><code>single-value</code>: the value is the range minimum and maximum</li><li><code>range</code>: the left value is the range minimum and the right value is the range maximum</li><li><code>at-most</code>: the range minimum is 0 and the range maximum is the value</li><li><code>at-least</code>: the range minimum is the value and the range maximum is <code>UINT64_MAX</code></li></ul><p>In the absence of <code>comparison</code>, the attribute value must not be less than the term range minimum and not more than the term range maximum. Comparisons include:</p><ul><li><code>eq</code>: attribute value is equal to the single-value term range.</li><li><code>neq</code>: attribute value is not equal to the single-value term range</li><li><code>lt</code>: attribute value is less than term-minimum</li><li><code>lte</code>: attribute value is less than or equal to term-minimum</li><li><code>gte</code>: attribute value is greater than or equal to term-maximum</li><li><code>gt</code>: attribute value is greater than term-maximum</li><li><code>in</code> (default): attribute value is a member of the term range</li><li><code>out</code>: attribute value is not a member of the term range</li></ul><h6 id="timestamp" tabindex="-1">Timestamp <a class="header-anchor" href="#timestamp" aria-label="Permalink to &quot;Timestamp&quot;">​</a></h6><p>A comma-delimited list of terms is defined for timestamp attributes, using an variation of the <a href="#numeric">numeric</a> format:</p><pre><code>    single-value ::= ( &lt;nanoseconds&gt; | &lt;timestamp&gt; )
</code></pre><p>All numeric comparisons are supported. A <code>timestamp</code> value will be converted to a <code>nanosecond</code> value using <code>CDateTime</code>, then numeric comparisons are applied.</p><h6 id="special-cases" tabindex="-1">Special Cases <a class="header-anchor" href="#special-cases" aria-label="Permalink to &quot;Special Cases&quot;">​</a></h6><ol><li>Index Events - FileId</li></ol><p>Index events using <code>FileId</code> can be filtered <a href="#numeric">numerically</a> using individual values or ranges.</p><p><a href="#text">Text</a> tokens may also be used to filter by:</p><ul><li>physical file path</li><li>storage plane</li><li>logical file name</li></ul><p>Text filtering by physical file path requires a preceding <code>FileInformation</code> that associates <code>FileId</code> with a <code>Path</code> matching the filter term token.</p><p>Text filtering by storage plane requires preceding instances of both <code>PlaneInformation</code> and <code>FileInformation</code>. The <code>FileId</code> is associated with the <code>FileInformation</code>&#39;s <code>Path</code>, which maps to the <code>PlaneInformation</code>&#39;s <code>Path</code>, which is paired with <code>Plane</code>.</p><p>Text filtering by logical file name also requires preceding instances of both <code>PlaneInformation</code> and <code>FileInformation</code>. The <code>FileId</code> is associated with the <code>FileInformation</code>&#39;s <code>Path</code>, which maps to the <code>PlaneInformation</code>&#39;s <code>Path</code>. The logical file name is derived from both <code>Path</code> values and <code>PlaneInformation</code>&#39;s <code>IsStriped</code> property.</p><ol start="2"><li>Index Events - NodeKind</li></ol><p>Events using <code>NodeKind</code> can be filtered by either the numerical value (0, 1, or 2) or the text equivalent (<em>branch</em>, <em>leaf</em>, <em>blob</em>, respectively). Text is converted to the numeric equivalent, and numeric values are compared. With only three valid values, number ranges are not supported but all other numeric comparisons are available.</p><p>Remember that <code>IndexPayload</code> does not use <code>NodeKind</code> but has an implied logical value of <code>LeafNode</code>. Likewise for <code>FileInformation</code>, even though the value has no meaning for the meta event. <code>NodeKind</code> cannot, by itself, be used to block all index events for leaf nodes.</p><ol start="3"><li>Index Events - Path</li></ol><p>Index events including the <code>Path</code> attribute can be filtered by wildcard patterns that resemble either a physical file path or a logical file name. Given a physical file path such as <code>/storage/plane/prefix/logical/file/path._N_of_M</code>, a filter term value of <code>logical::file::path</code> is treated as <code>*/logical/file/path*</code>.</p><ol start="4"><li>TraceID Attribute</li></ol><p>All events may include a <code>TraceId</code> attribute, subject to options specified when recording started. Many, but not all, events are recorded within the scope of <code>QueryStart</code> and <code>QueryStop</code> events, which means the <code>TraceId</code> is associated with a <code>ServiceName</code> attribute. <code>TraceId</code> filter terms can include service names, resulting in the acceptance of all <code>TraceId</code> values associated with the named services.</p><p>Where the distinction between <code>FileId</code> and <code>Path</code> is naturally disambiguated by their data types, both <code>TraceId</code> and <code>ServiceName</code> are text. Term tokens are not disambiguated. A token pattern that matches both a trace ID and a service name will accept both the ID and name.</p><h3 id="ieventmodel" tabindex="-1">IEventModel <a class="header-anchor" href="#ieventmodel" aria-label="Permalink to &quot;IEventModel&quot;">​</a></h3><p>An extension of <code>IEventVisitationLink</code>, this abstraction describes visitors whose purpose is to more broadly transform the event stream. Possible changes include:</p><ul><li>event suppression, as with a filter (e.g., an <code>IndexEviction</code> might be discarded); or</li><li>attribute updates (e.g., an <code>ExpandTime</code> may be replaced with an estimate assuming a different decompression algorithm); or</li><li>event reclassification (e.g., an <code>IndexCacheHit</code> may become an <code>IndexCacheMiss</code>); or</li><li>event creation (e.g., an <code>IndexLoad</code> may be required after reclassifying <code>IndexCacheHit</code> to <code>IndexCacheMiss</code>).</li></ul><h4 id="cindexeventmodel" tabindex="-1">CIndexEventModel <a class="header-anchor" href="#cindexeventmodel" aria-label="Permalink to &quot;CIndexEventModel&quot;">​</a></h4><p>A concrete implementation of <code>IEventModel</code> that acts on events in the <code>EventCtxIndex</code> event context. All other events are propagated without change.</p><p>The options for stream transformation are extensive.</p><ul><li><code>ReadTime</code> values are replaced with estimates defined for alternate storage planes. Branch and leaf nodes for each file may be assigned a storage plane. <em>This is currently mandatory, but is so only because it was the first transformation to be implemented. Should it remain mandatory, or should it become optional like other transformations?</em></li><li><code>ReadTime</code> values may be replaced instead by an estimate assuming the use of a page cache.</li><li><code>InMemorySize</code> and <code>ExpandTime</code> values may be replaced with estimates as if a different compression algorithm had been used in the original event. One set of estimates per index node kind is supported, so branch and leaf nodes can be compressed with different algorithms.</li><li><code>InMemorySize</code> and <code>ExpandTime</code> values may be changed to simulate different decompression strategies. For events recorded when node decompression is reported with <code>IndexLoad</code> events, the effects of decompression may be deferred to <code>IndexPayload</code> events. This results in reduced node cache size and avoids unnecessary decompression, but with the risk of repeated decompressions. This can be enabled separately for branch and leaf nodes.</li><li>The effects of changing the node cache size can be simulated, with different limits for branch and leaf nodes. This option radically alters the event stream: <ul><li>An <code>IndexCacheHit</code> event may be replaced by an <code>IndexCacheMiss</code>, <code>IndexLoad</code>, and zero or more <code>IndexEviction</code> events.</li><li>An <code>IndexCacheMiss</code> event may be replaced by an <code>IndexCacheHit</code> event. The next <code>IndexLoad</code> event for the same node will then be suppressed.</li><li>And <code>IndexLoad</code> event may be followed by one or more <code>IndexEviction</code> events.</li><li>An input <code>IndexEviction</code> event is always suppressed.</li></ul></li></ul><p>Some events may be discarded by the model if they are observed when unexpected. Modeling and <em>on-demand</em> node expansion from <em>on-load</em> events and custom node cache sizes imposes a need for information made available in <code>IndexCacheHit</code> and <code>IndexLoad</code> events. <code>IndexLoad</code> events are expected to follow <code>IndexCacheMiss</code> events. <code>IndexLoad</code> events not preceded by either a cache hit or miss for the same node are discarded. <code>IndexPayload</code> and <code>IndexEviction</code> events not preceded by either a cache hit or the combination of a cache miss and load for the same node are discarded.</p><p>Model options are specified using a property tree. The configuration conforms to this format:</p><pre><code>@kind
</code></pre><p>An optional identifier that must be <code>index-events</code> when present.</p><pre><code>storage/
</code></pre><p>Required container for storage plane and page cache configuration settings.</p><pre><code>storage/
    @cacheReadTime
    @cacheCapacity
</code></pre><p>Optional page cache controls. Setting a positive read time enables the page cache. Setting a positive capacity limits the total size of cached pages. Note that unlike a real page cache, which would cache the entire page, the model merely tracks which 8 KB pages are cached based on file ID and offset.</p><p><strong>If not zero, the capacity must be at least 8 KB. It is an error to configure the page cache such that it cannot cache at least one page.</strong></p><pre><code>storage/
    @dynamicCacheCapacity
</code></pre><p>The page cache capacity can be dynamically configured relative to the combined sizes of all in-memory node caches. When <code>@cacheReadTime</code> enables the page cache, when <code>@cacheCapacity</code> is omitted (or zero), and the sum of <code>//memory/node/@cacheCapacity</code> is less than <code>@dynamicCacheCapacity</code>, the page cache capacity is set to the difference of <code>@dynamicCacheCapacity</code> and the sum of <code>//memory/node/@cacheCapacity</code>. This property cannot enable the page cache, nor can it override an explicitly defined capacity. If the capacity would be set to a non-zero value less than the size of a page, making the cache incapable of holding a page, the capacity instead remains zero.</p><p>Consider this example:</p><div class="language-yaml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">storage</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">  cacheReadTime</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">10000</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">  dynamicCacheCapacity</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">40 MiB</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">memory</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">  node</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  - </span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">kind</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">0</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">    cacheCapacity</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">0.5 MiB</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  - </span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">kind</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">1</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">    cacheCapacity</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">20 MiB</span></span></code></pre></div><p>In this example, the node caches are allotted 20.5 MiB. The page cache is dynamically allotted the balance of 40 MiB, or 19.5 MiB.</p><pre><code>storage/
    plane/
</code></pre><p>Required and repeatable element container for a single storage plane. The first occurrence becomes the default plane for any file that is not explicitly assigned a plane.</p><pre><code>storage/
    plane/
        @name
</code></pre><p>Required unique identifier through which files identify the plane or planes they use.</p><pre><code>storage/
    plane/
        @readTime
</code></pre><p>Required number of nanoseconds needed to load a single 8KB page from the storage device.</p><pre><code>storage/
    file/
</code></pre><p>Optional repeatable element enabling one or all files to be explicitly associated with a storage plane.</p><pre><code>storage/
    file/
        @path
</code></pre><p>Optional unique file path identifying the physical file being configured. When present, the value must match the value presented in the<code>Path</code> attribute of a <code>FileInformation</code> meta event. Omission, or empty, applies this configuration to all files not explicitly configured in a sibling element.</p><pre><code>storage/
    file/
        @plane
</code></pre><p>Optional storage plane name identifies the storage device on which the file is stored. When present, the value must match one of the configured storage plane names. Omission, or empty, associates the file or files to the default plane</p><pre><code>storage/
    file/
        @branchPlane
        @leafPlane
        @blobPlane
</code></pre><p>Optional storage plane names associating all nodes of a given kind to a storage plane. When present, the value must match one of the configured storage plane names. Omission, or empty, with the default plane for the file.</p><pre><code>memory/
</code></pre><p>Optional container for decompression performance estimates, decompression strategies, and node cache settings.</p><pre><code>memory/
    node/
</code></pre><p>The optional configuration of memory expansion modeling for each index node kind:</p><ul><li><p>Expansion mode modeling may override the default <code>expansionMode</code> by including a <code>expansionMode</code> property. The default is inherited from the parent element.</p></li><li><p>Expansion estimation must include both <code>sizeFactor</code> and <code>sizeToTimeFactor</code> properties. No defaults are defined. These properties must be specified for every node kind to enable estimation.</p></li><li><p>Node cache size control must include a <code>cacheCapacity</code> property.</p><p>memory/ node/ @kind</p></li></ul><p>One of zero or &quot;branch&quot; for branch nodes. One of one or &quot;leaf&quot; for leaf nodes. One of two or &quot;blob&quot; for blob nodes.</p><p>In all cases, the numeric value takes precedence over the text equivalent. A <code>node</code> without <code>@kind</code> is ignored.</p><pre><code>memory/
    node/
        @sizeFactor
        @sizeToTimeFactor
</code></pre><p>Optional controls for decompression performance estimates for the desginated node kind. To enable compression estimates, both values must be specified for all node types. Both values must be omitted for all node types to proceed without estimations. Every other combination of these values is an error.</p><p>Both values are positive decimal (i.e., floating point) numbers. The estimated <code>InMemorySize</code> for a decompressed node is the product of the size factor and 8 KB. The estimated <code>ExpandTime</code> for the same node is the product of the estimated <code>InMemorySize</code> and the size to time factor.</p><pre><code>memory/
    node/
        @expansionMode
</code></pre><p>Optional choice of:</p><ul><li><code>ll</code>: The model input and output are both assumed to represent node expansion on-load. This is the default.</li><li><code>ld</code>: The model input is assumed to represent node expansion on-load, and the model output represents node-expansion on-demand.</li><li><code>dd</code>: The model input and output are both assumed to represent node expansion on-demand.</li></ul><p>This does not apply to branch nodes, which always use <em>on-load</em> expansion.</p><pre><code>memory/
    node/
        @cacheCapacity
</code></pre><p>Optional upper limit, in bytes, for a node cache for nodes of the desginated kind. Omission, empty, or zero, prevents the model from caching. Note the discrepancy between this capacity and the page cache capacity reflects the page cache&#39;s requirement for a separately configured time duration. Note that unlike a real node cache, which would cache the entire page, the model caches the size, in bytes, of the node as it is stored in memory.</p><p><strong>If not zero, the capacity must be at least the size of the largest node size. It is an error to configure the page cache such that it cannot cache at least one page, but the error will not be detected until an offending node is observed.</strong></p><pre><code>memory/
    observed/
</code></pre><p>Optional and repeatable element to be used by unit tests to pre-populate the memory model&#39;s internal data. Its use simplifies the establishment of cache preconditions when evaluating the effects of the model&#39;s cache on the event stream.</p><p>Each instance represents one loaded page. The data has value for both alternate decompression strategies and node caching.</p><p>It is worth noting that element attributes follow the title case naming convention instead of the camel case used in the rest of the configuration. This is intentional, as the names match the event attribute names from which the model would normally be updated.</p><pre><code>memory/
    observed/
        @NodeKind
        @FileId
        @FileOffset
</code></pre><p>These identify the node and the cache to which it belongs. The node may be the same as or differ from nodes referenced by input events.</p><pre><code>memory/
    observed/
        @ExpandTime
</code></pre><p>The number of nanoseconds required to expand the node one time. For nodes also referenced in input events, this value may differ from what is used in those events. The model may always replace the value with an estimated value. If not replaced, the model accepts that decompression times can vary based on system load and always keeps the last observed time.</p><pre><code>memory/
    observed/
        @InMemorySize
</code></pre><p>If algorithm estimation is enabled, the value is replaced. If the node will not be referenced by model input events, the value can be any positive integral value. Otherwise, the value must match the first non-zero <code>InMemorySize</code> value observed in an input event. Node sizes are not expected to change between observations, and the model does not account for unexpected changes. Once a node is in the cache with size <code>X</code>, it must always have size <code>X</code>.</p><h3 id="cmetainfostate-ccollector" tabindex="-1">CMetaInfoState::CCollector <a class="header-anchor" href="#cmetainfostate-ccollector" aria-label="Permalink to &quot;CMetaInfoState::CCollector&quot;">​</a></h3><p><code>CMetaInfoState</code> provides a runtime repository of event-defined state information, including values from the <code>FileInformation</code> and <code>QueryStart</code> events. As a concrete implementation of <code>IEventVisitationLink</code>, <code>CCollector</code> is a companion class that extracts event data for the repository.</p><p>To avoid data loss, this link must precede all other links. It is the responsibility of event iterating code to ensure this requirement is satisfied.</p><p>The repository is available to all operations and all other visitors. The collector itself is not.</p><h1 id="ceventvisitationlinktester" tabindex="-1">CEventVisitationLinkTester <a class="header-anchor" href="#ceventvisitationlinktester" aria-label="Permalink to &quot;CEventVisitationLinkTester&quot;">​</a></h1><p>A concrete implementation of <code>IEventVisitor</code> used to test iterated events. Given an <em>expected</em> event iterator, each visited event is compared with the next expected event. Any discrepancy is a unit test failure.</p><h1 id="ceventconsumingop" tabindex="-1">CEventConsumingOp <a class="header-anchor" href="#ceventconsumingop" aria-label="Permalink to &quot;CEventConsumingOp&quot;">​</a></h1><p>An abstract base class for handling requests to traverse and act upon an event data file. It provides common handling of an input event file name, an output stream for text output, an optional single occurrence of event filters, an optional single event model, and one CMetaInfoState. When using the traverseEvents method, the meta state instance is guaranteed to be the first visitor in the visitation chain, before the optional event filter.</p><p>Whether events are filtered before or after an event model is hard coded. Filtering applies after a model so model-generated events can be filtered. Subclasses needing more control are responsible for hiding the relevant base methods.</p><h2 id="cindexplotop" tabindex="-1">CIndexPlotOp <a class="header-anchor" href="#cindexplotop" aria-label="Permalink to &quot;CIndexPlotOp&quot;">​</a></h2><p>A concrete implementation of <a href="#ceventconsumingop">CEventConsumingOp</a> that uses a configuration property tree to produce one or more chart data sets from one or more binary event files. A data set is a one or two dimensional array of generated numeric values. Each cell value is derived from the set of events which match both horizontal and vertical criteria. The event set is referred to as a bucket.</p><p>A list of visitation link configurations determines which events are available for data set inclusion. Links include event filters and index event models. At least one link is required.</p><p>A value selector chooses the numeric value to be generated for each cell. The accepted choices are hard-coded. An explicit choice is required.</p><p>An X axis configuration defines the data set columnar buckets. A configuration is required.</p><p>A Y axis configuration defines the data set row buckets. If omitted, a single bucket containing all events is assumed.</p><p>Multiple data set variant configurations may be configured to create multiple data sets. Each data set is based on the same value selector and axis configurations. This allows multiple versions of the same data set to be generated for either different inputs or different link configurations. Multiple operations are required to produce data sets using different value selectors or axis values.</p><p>What questions can be answered using chart data sets?</p><ol><li>What happened? A data set is a visual representation of recorded event activity. All cell values are computed from one iteration of specifed input events. A second iteration might be required to identify the proper axis buckets. Input events might be filtered, but are otherwise unchanged.</li><li>What might have happened? Similar to &quot;what happened?&quot;, an event model transforms the raw input stream into a projection of what would have been observed if the recording process had been configured differently.</li><li>Which configuration might be &quot;best&quot;? Each cell value is the product of one input iteration where the events are transformed by visitation links tweaked for each cell by a combination of variant, columnar, and row adjustments.</li></ol><p>The operation is focused on comparing configurations. Each input iteration produces a singular value. Some &quot;what happened&quot; questions can be answered, albeit inefficiently. Others, such as activity over time, cannot be answered at this time.</p><p>The configuration format is as follows:</p><pre><code>/operation/
/command/
</code></pre><p>Preferred and alternate root configuration elements. The <em>command</em> terminology comes from <code>evtool</code>, the operation&#39;s initial host process. <code>operation</code> is preferred. The names are interchangeable.</p><pre><code>/operation/@name
</code></pre><p>Required identifier denoting the operation for which the configuration applies. The value must be <code>index.plot</code>.</p><pre><code>/operation/input/
</code></pre><p>Optional repeatable file path element specifying default files for event iteration. Values specified here can be overridden by <code>plot/input</code>, <code>x-axis/iteration/input</code>, and/or <code>y-axis/iteration/input</code>. When not specified anywhere in the configuration, the operation&#39;s host process is responsible for supplying values.</p><p>Paths specified in the configuration file may be relative or absolute. Wildcard resolution is not supported. When <code>evtool</code> is the host, wildcard resolution may be provided by the shell. Configurations without inputs are more easily reused, but do not have the flexibility of designating distinct files for data set, row, or column. Filters can be used to simulate the outcome, but iteration of all elements from all potential files is time consuming.</p><pre><code>/operation/@input
</code></pre><p>Optional file path to a binary event file. This remains for backward compatibility with original files. It is equivalent to one instance of the <code>input</code> element.</p><pre><code>/operation/@valueSelector
</code></pre><p>Required designation of which value will be accumulated for each plot. Must be one of these case insensitive choices:</p><ul><li><p>readTime: the ReadTime attribute from IndexLoad events is accumulated</p></li><li><p>expandTime: the ExpandTime attribute from IndexLoad events is accumulated</p></li><li><p>elapsedTime: the sum of the ReadTime and ExpandTime attributes from IndexLoad events is accumulated</p></li><li><p>cacheMisses: the number of IndexCacheMiss events is counted</p><p>/operation/link/</p></li></ul><p>Required repeatable element specifying a valid visitation link configuration. Each supported visitiation link configuration is described elsewhere in this document. This section focuses on values needed by the operation.</p><pre><code>/operation/link/@kind
/operation/link/@id
</code></pre><p>A link kind controls which visitation link class to create. Its id distinguishes instances of link configurations with the same kind. Configuring both pre-model and post-model event filters is permitted. Both values are conditionally required.</p><p>If <code>@kind</code> is omitted, an <a href="#cindexeventmodel">index model</a> configuration denoted as <code>index-events</code> is assumed. To configure an <a href="#ceventfilter">event filter</a>, the value must be given as <code>event-filter</code>.</p><p>An <code>@id</code> is required only when <code>@kind</code> does not uniquely identify the link configuration instance and the operation intends to manipulate the configuration.</p><p>A link configuration node is identified by combining the two values using a dotted notation like <code>&lt;kind&gt; [ &#39;.&#39; &lt;id&gt; ]</code>. The link kind is sufficient when only one instance with the value is configured.</p><pre><code>/operation/plot/
</code></pre><p>Optional repeatable root element of a data set variation. When present it must contain at least one <code>delta</code> or <code>input</code> child element.</p><pre><code>/operation/plot/@name
</code></pre><p>Required label differentiating one variation from another. Uniqueness is neither required nor enforced.</p><pre><code>/operation/plot/delta/
</code></pre><p>Conditional repeatable element describing a single visitation link change.</p><p>At least one <code>delta</code> or one <code>input</code> is required. Both are permitted.</p><pre><code>/operation/plot/delta/@linkId
</code></pre><p>Optional visitation link identifier. If omitted or empty, <code>index-events</code> is assumed.</p><pre><code>/operation/plot/delta/@xpath
</code></pre><p>Required XPath into the identified visitation link configuration, where <code>link</code> is the root element.</p><pre><code>/operation/plot/delta/@value
</code></pre><p>Optional visitation link configuration value. If omitted, the XPath is removed.</p><pre><code>/operation/plot/input/
</code></pre><p>Conditional repeatable input file path element. Default input file events are unchanged if omitted and replaced for each data set cell when given. Axis level input file path settings cannot remove event files specified here.</p><p>At leasrt one <code>input</code> or one <code>delta</code> is required. Both are permitted.</p><pre><code>/operation/x-axis/
</code></pre><p>Required root element describing X axis columnar values.</p><pre><code>/operation/x-axis/@linkId
/operation/x-axis/@xpath
</code></pre><p>Optional default visitation link identifier and change location for each axis column. <code>@xpath</code> applies to every column that does not explicitly set its own value. <code>@linkId</code> applies to any column that omits both <code>@xpath</code> and <code>@linkId</code>.</p><pre><code>/operation/x-axis/iteration/
</code></pre><p>Conditional repeatable column definition.</p><pre><code>/operation/x-axis/iteration/@name
</code></pre><p>Optional custom column label. When omitted or empty the label will be:</p><ul><li><p>the value of <code>delta/@value</code> when exactly one instance of <code>delta</code> is configured; or</p></li><li><p><code>ambiguous</code> when zero or multiple instances of <code>delta</code> are configured.</p><p>/operation/x-axis/iteration/delta/</p></li></ul><p>Conditional repeatable column definition. Each iteration must contain at least one <code>delta</code> or at least one <code>input</code> element.</p><pre><code>/operation/x-axis/iteration/delta/@linkId
</code></pre><p>Optional visitation link identifier. If omitted or empty, <code>index-events</code> is assumed.</p><pre><code>/operation/x-axis/iteration/delta/@xpath
</code></pre><p>Required XPath into the identified visitation link configuration, where <code>link</code> is the root element.</p><pre><code>/operation/x-axis/iteration/delta/@value
</code></pre><p>Optional visitation link configuration value. If omitted, the XPath is removed.</p><pre><code>/operation/x-axis/iteration/input/
</code></pre><p>Conditional repeatable input file path element. Default input file events are unchanged if omitted and replaced for each data set cell when given. Can be combined with <code>plot</code> and <code>y-axis</code> inputs.</p><pre><code>/operation/x-axis/value/
</code></pre><p>Conditional repeatable values used in combination with <code>x-axis/@xpath</code> and <code>xpath/@linkId</code>. Ignored in the presence of <code>x-axis/iteration</code>. This is shorthand markup to specify column values that all depend on exactly one visitation link configuration change.</p><p>Cannot be used if:</p><ul><li><p><code>x-axis/iteration</code> is present</p></li><li><p>a custom column name is needed</p></li><li><p>custom inputs are needed</p></li><li><p>multiple visitation link configuration changes are needed</p><p>/operation/x-axis/@minValue /operation/x-axis/@maxValue /operation/x-axis/@steps</p></li></ul><p>Conditional values used in combination with <code>x-axis/@xpath</code> and <code>x-axis/@linkId</code>. Ignored in the presence of either <code>x-axis/iteration</code> or <code>x-axis/value</code>. This is shorthand markup to dynamically compute uniformly distributed column values dependent upon a single visitation link configuration change.</p><p>Cannot be used if:</p><ul><li><code>x-axis/iteration</code> is present</li><li><code>x-axis/value</code> is present</li><li>a custom column name is needed</li><li>custom inputs are needed</li><li>multiple visitation link configuration changes are needed</li></ul><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>    /operation/y-axis/</span></span></code></pre></div><p>Optional root element defining row buckets. If omitted, the data set will have one implied row bucket. Element content matches the definition of <code>x-axis</code>, with the obvious exception that <code>x-axis</code> references to columns are to be interpreted as row references.</p><h2 id="cindexfilesummary" tabindex="-1">CIndexFileSummary <a class="header-anchor" href="#cindexfilesummary" aria-label="Permalink to &quot;CIndexFileSummary&quot;">​</a></h2><p>A concrete implementation of <code>CEventConsumingOp</code> that collects statistics about the index events it visits. As the previous statement suggests, it is also an event visitor although this is a private implementation detail.</p><p>Statistics are collected per index node. Values include memory usage, event counters, read timing (total, minimum, maximum, and average read time), and expansion timing (total, minimum, maximum, and average).</p><p>The index node statistics can be aggregated by file ID or node kind. Grouping by file ID reveals branch and leaf activity for every observed file. Grouping by node kind provides model configuration guidance for cache sizes, expansion estimations, and storage plane performance.</p><h2 id="testop" tabindex="-1">TestOp <a class="header-anchor" href="#testop" aria-label="Permalink to &quot;TestOp&quot;">​</a></h2><p>A concrete implementations of <code>CEventConsumingOp</code> used with unit tests. Defined within <code>testEventVisitationLinks</code>, the <code>doOp</code> method assembles the configured visitation chain and iterates the configured input events. The visitation chain begins with the inherited <a href="#cmetainfostate">meta state</a> link, any explicitly configured links, and ends with the <a href="#ceventvisitationlinktester">test visitor</a>.</p><p>The only base functionality used by this class is the meta state link. The model and filter instances are ignored, as are the input file path and output stream.</p><h2 id="stubop" tabindex="-1">StubOp <a class="header-anchor" href="#stubop" aria-label="Permalink to &quot;StubOp&quot;">​</a></h2><p>A concrete implementation of <code>CEventConsumingOp</code> that does nothing. It exists as a placeholder in unit tests that directly instantiate visitation links that require an operation. Attempting to use the operation is an error that throws an exception.</p><h1 id="ieventiterator" tabindex="-1">IEventIterator <a class="header-anchor" href="#ieventiterator" aria-label="Permalink to &quot;IEventIterator&quot;">​</a></h1><p>Where <code>IEventVisitor</code> has events pushed to it, this interface allows its user to pull events from a source on demand. The <code>IEventReader</code> interface in <code>/system/jlib/jevent.hpp</code> describes an event pulling mechanism. This is an abstraction modeled on <code>IEventReader</code> for pulling events from arbitrary event sources.</p><p>Iteration occurs using the <code>nextEvent</code> method. Other methods provide access to information provided by <code>IEventVisitor::visitFile</code> and <code>IEventVisitor::departFile</code>.</p><p>Whereas standard library iteratorss tend to feature begin and end semantics, and jlib iterators use first and next, the event iterator relies solely on <code>nextEvent</code>. Event file consumers, of which the file iterator is one example, offer only a <code>nextEvent</code> option because they don&#39;t go back to previously read content. Iteration, then, can be implemented as</p><div class="language-cpp vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">cpp</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">    while</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> (iter.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">nextEvent</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(event))</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">        visitor.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">visitEvent</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(event);</span></span></code></pre></div><p>Note that this snippet assumes the visitor will not attempt to abort event traversal by returning <em>false</em>. A check for <em>false</em> can easily be included if needed.</p><h2 id="ceventmultiplexer" tabindex="-1">CEventMultiplexer <a class="header-anchor" href="#ceventmultiplexer" aria-label="Permalink to &quot;CEventMultiplexer&quot;">​</a></h2><p>Implementation of <code>IEventIterator</code> that uses other iterators as event sources, merging events from each source into a single output event stream in chronological order.</p><p>Merging events from multiple sources is not intuitive, at least not when index events are included. The file ID associated with an index file path cannot be predicted. Assuming two event inputs that reference paths <code>foo</code> and <code>bar</code>, the file IDs associated with <code>foo</code> may not be the same in each input. In fact, the ID&#39;s for <code>foo</code> and <code>bar</code> could be swapped between inputs.</p><p>To address this, within each input each distinct FileId attribute value is replaced with a unique number. In other words, within an input file every occurrence of FileId <code>N</code> is replaced with <code>M</code>, and across all inputs substitute value <code>M</code> is only used with one index file.</p>`,232)])])}const u=t(n,[["render",s]]);export{m as __pageData,u as default};
